const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json({ limit: '10mb' }));

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme'
  }
});

function buildBaseQuery(searchParams) {
  const { query, fields, filters, fuzzy, boost } = searchParams;
  
  let baseQuery = { bool: { must: [], filter: [], should: [] } };

  if (query) {
    if (fields && fields.length > 0) {
      baseQuery.bool.must.push({
        multi_match: {
          query: query,
          fields: fields,
          type: fuzzy ? 'best_fields' : 'most_fields',
          fuzziness: fuzzy ? 'AUTO' : undefined,
          boost: boost || 1
        }
      });
    } else {
      baseQuery.bool.must.push({
        query_string: {
          query: query,
          default_operator: 'AND'
        }
      });
    }
  }

  if (filters) {
    if (filters.term) {
      Object.entries(filters.term).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ term: { [field]: value } });
      });
    }
    
    if (filters.terms) {
      Object.entries(filters.terms).forEach(([field, values]) => {
        baseQuery.bool.filter.push({ terms: { [field]: values } });
      });
    }
    
    if (filters.range) {
      Object.entries(filters.range).forEach(([field, rangeParams]) => {
        baseQuery.bool.filter.push({ range: { [field]: rangeParams } });
      });
    }
    
    if (filters.exists) {
      filters.exists.forEach(field => {
        baseQuery.bool.filter.push({ exists: { field: field } });
      });
    }
    
    if (filters.wildcard) {
      Object.entries(filters.wildcard).forEach(([field, pattern]) => {
        baseQuery.bool.filter.push({ wildcard: { [field]: pattern } });
      });
    }
    
    if (filters.regexp) {
      Object.entries(filters.regexp).forEach(([field, pattern]) => {
        baseQuery.bool.filter.push({ regexp: { [field]: pattern } });
      });
    }
  }

  if (baseQuery.bool.must.length === 0 && baseQuery.bool.filter.length === 0) {
    return { match_all: {} };
  }

  return baseQuery;
}

function buildScriptScoreQuery(baseQuery, scriptConfig) {
  const { source, params, lang } = scriptConfig;
  
  return {
    script_score: {
      query: baseQuery,
      script: {
        source: source,
        params: params || {},
        lang: lang || 'painless'
      },
      min_score: scriptConfig.min_score,
      boost: scriptConfig.boost
    }
  };
}

function buildFunctionScoreQuery(baseQuery, functionConfig) {
  const query = {
    function_score: {
      query: baseQuery,
      functions: [],
      score_mode: functionConfig.score_mode || 'multiply',
      boost_mode: functionConfig.boost_mode || 'multiply',
      max_boost: functionConfig.max_boost,
      min_score: functionConfig.min_score
    }
  };

  if (functionConfig.functions) {
    functionConfig.functions.forEach(func => {
      const scoringFunction = {};
      
      if (func.filter) {
        scoringFunction.filter = func.filter;
      }
      
      if (func.weight) {
        scoringFunction.weight = func.weight;
      }
      
      if (func.script_score) {
        scoringFunction.script_score = {
          script: {
            source: func.script_score.source,
            params: func.script_score.params || {},
            lang: func.script_score.lang || 'painless'
          }
        };
      }
      
      if (func.field_value_factor) {
        scoringFunction.field_value_factor = func.field_value_factor;
      }
      
      if (func.decay) {
        const decayType = func.decay.type || 'gauss';
        scoringFunction[decayType] = {
          [func.decay.field]: {
            origin: func.decay.origin,
            scale: func.decay.scale,
            offset: func.decay.offset,
            decay: func.decay.decay
          }
        };
      }
      
      if (func.random_score) {
        scoringFunction.random_score = func.random_score;
      }
      
      query.function_score.functions.push(scoringFunction);
    });
  }

  return query;
}

function buildAggregations(aggConfig) {
  const aggregations = {};
  
  if (aggConfig) {
    Object.entries(aggConfig).forEach(([aggName, aggDef]) => {
      aggregations[aggName] = aggDef;
    });
  }
  
  return aggregations;
}

function buildHighlight(highlightConfig) {
  if (!highlightConfig) return undefined;
  
  return {
    fields: highlightConfig.fields || {},
    pre_tags: highlightConfig.pre_tags || ['<em>'],
    post_tags: highlightConfig.post_tags || ['</em>'],
    number_of_fragments: highlightConfig.number_of_fragments,
    fragment_size: highlightConfig.fragment_size
  };
}

app.post('/api/search', async (req, res) => {
  try {
    const {
      index,
      searchParams,
      scriptScore,
      functionScore,
      aggregations,
      highlight,
      sort,
      from = 0,
      size = 10,
      source,
      trackScores = true
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const baseQuery = buildBaseQuery(searchParams || {});
    
    let finalQuery = baseQuery;
    
    if (scriptScore) {
      finalQuery = buildScriptScoreQuery(baseQuery, scriptScore);
    } else if (functionScore) {
      finalQuery = buildFunctionScoreQuery(baseQuery, functionScore);
    }

    const searchBody = {
      query: finalQuery,
      from: from,
      size: size,
      track_scores: trackScores
    };

    if (aggregations) {
      searchBody.aggs = buildAggregations(aggregations);
    }

    if (highlight) {
      searchBody.highlight = buildHighlight(highlight);
    }

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    const result = await esClient.search({
      index: index,
      body: searchBody
    });

    res.json({
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight,
        sort: hit.sort
      })),
      aggregations: result.aggregations,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({
      error: 'Search failed',
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

